(5, 7, 'ativo', 78540.00, 'Único dono, IPVA pago', 0, NULL, 'Carro', 'Hyundai', 'HB20 Comfort Plus', 2025, 2025, 12231, 'seminovo', 'Manual', '1.0', 4, 'Hatch', 'Flex', 'Dianteira', 'Prata', '\"[\\\"Ar-condicionado\\\",\\\"Airbag\\\",\\\"ABS\\\",\\\"Multimídia\\\",\\\"Câmera de ré\\\",\\\"Sensor de estacionamento\\\",\\\"Bancos em couro\\\"]\"', '2026-05-05 06:19:03');
