INSERT INTO `seo_templates` (`id`, `pagina`, `titulo`, `descricao`, `keywords`, `texto_h1`, `texto_conteudo`, `link_canonico`, `ativo`, `criado_em`) VALUES
(1, 'home', 'TEMCAR | Comprar e vender carros usados e novos no Brasil', 'Ofertas de carros usados, novos, e seminovos à venda em todo o Brasil. Compare preços, fale com vendedores e anuncie grátis no TEMCAR.', '', 'TEMCAR - Comprar e vender carros usados, novos e seminovos', '', 'https://www.temcar.com.br/', 1, '2026-04-24 23:46:27'),
(2, 'quem_somos', 'Quem Somos | TEMCAR', 'O TEMCAR é uma plataforma de marketplace do setor automotivo que visa promover maior eficiência e praticidade na relação de compra e venda de veículos e motos no Brasil.', '', 'Quem Somos', '', 'https://www.temcar.com.br/quem-somos/', 1, '2026-04-24 23:53:47'),
(3, 'fale_conosco', 'Fale Conosco | TEMCAR', 'Se você tem alguma dúvida, comentário, sugestão, ou deseja expressar sua opinião, entre em contato com a gente. Será um prazer receber sua mensagem', '', 'fale conosco', '', 'https://www.temcar.com.br/fale-conosco/', 1, '2026-04-24 23:59:18'),
(4, 'regras_gerais', 'Regras Gerais | TEMCAR', 'O presente termo regula as condições gerais para uso dos serviços que são oferecidos pelo portal TEMCAR (www.temcar.com.br) ', '', 'regras gerais', '', 'https://www.temcar.com.br/regras-gerais', 1, '2026-04-25 00:02:40'),
(5, 'politica_privacidade', 'Política de Privacidade | TEMCAR', 'A presente Política regula as condições gerais de coleta, uso, armazenamento, tratamento e proteção de dados no portal TEMCAR (www.temcar.com.br)', '', 'Política de Privacidade', '', 'https://www.temcar.com.br/politica-de-privacidade/', 1, '2026-04-25 00:05:36'),
(6, 'termos_uso', 'Termos de Uso | TEMCAR', 'Termos de uso. O presente termo regula as condições gerais para uso dos serviços que são oferecidos pelo portal TEMCAR (www.temcar.com.br)', '', 'Termos de Uso', '', 'https://www.temcar.com.br/termos-de-uso/', 1, '2026-04-25 00:08:35'),
(7, 'revenda', '#revenda - Carros Usados e Seminovos em #cidade', 'Confira os veículos à venda na #revenda em #cidade, #estado. Encontre carros novos, seminovos e usados com os melhores preços.', 'temcar, carro, moto, vender carro, carro novo, carro seminovo, carro usado', 'Revendas', '', '', 1, '2026-04-25 00:13:11'),
(8, 'buscar_revendas', 'Revendas de Carros e Motos no Brasil | Lojas e Concessionárias - TEMCAR', 'Encontre revendas, lojas e concessionárias de carros, motos e caminhões em todo o Brasil. Veja contatos, estoque e veículos disponíveis na TEMCAR.', 'temcar, carro, moto, vender carro, carro novo, carro seminovo, carro usado', 'Buscar Revendas de Veículos', '', 'https://www.temcar.com.br/buscar-revendas/carros-e-motos/', 1, '2026-04-25 00:15:26'),
(9, 'cadastro_particular', 'Cadastro Particular | TEMCAR', 'Crie sua conta particular no TEMCAR e anuncie seu veículo gratuitamente. Cadastro rápido para vender seu carro.', 'temcar, carro, moto, vender carro, carro novo, carro seminovo, carro usado', 'Cadastro Particular', '', '', 1, '2026-04-25 00:19:57'),
(10, 'cadastro_revenda', 'Cadastre sua Revenda | TEMCAR', 'Cadastre sua revenda no TEMCAR e comece a anunciar veículos. Preencha o formulário e tenha acesso ao painel de administração.', 'temcar, carro, moto, vender carro, carro novo, carro seminovo, carro usado', 'Cadastre sua Revenda', '', 'https://www.temcar.com.br/cadastro-revenda', 1, '2026-04-25 00:25:56'),
(13, 'anunciar', 'Venda seu carro no TEMCAR', 'O TEMCAR é uma plataforma virtual voltada para negociaçõe de compra e venda de carros novos e Usados, motos e caminhões. ', 'temcar, carro, moto, vender carro, carro novo, carro seminovo, carro usado', 'Anunciar Carro', '', 'https://www.temcar.com.br/anunciar', 1, '2026-04-25 01:54:06'),
(14, 'planos', 'Planos para Anunciar seu Carro no TEMCAR', 'No TEMCAR você encontra o plano ideal para divulgar venda de veículos, você pode optar por um plano grátis ou um plano pago com maior destaque na exibição', 'temcar, carro, moto, vender carro, carro novo, carro seminovo, carro usado', 'Planos de Anúncio', '', '', 1, '2026-04-25 02:00:22'),
(17, 'venda', 'Comprar #marca #modelo Usado - #cidade, #estado', 'Comprar #marca #modelo usado em #cidade e região, #estado. Veja fotos, preço e detalhes do veículo no TEMCAR.', '', 'Carros à venda', '', 'https://www.temcar.com.br/venda/#marca/#modelo/#cidade/#estado', 1, '2026-04-25 04:55:39'),
(42, 'criar_conta', 'Crie sua Conta no TEMCAR', 'Qual o tipo de conta você deseja criar, particular ou revenda? Faça parte da melhor plataforma de venda de carros no Brasil', 'carros usados, carros novos, carros seminovos, venda de carros, comprar carro, anunciar carro, carros seminovos, revendas de carros, classificados de carros', '', '', 'https://www.temcar.com.br/anunciar', 1, '2026-04-30 03:00:53'),
(43, 'buscar_cidades', 'Venda de Carros em #cidade, #estado | TEMCAR', 'Explore cidades com carros, motos e caminhões à venda no TEMCAR. Encontre veículos disponíveis na sua região.', 'buscar cidades, carros à venda por cidade, veículos por região, temcar', 'Buscar Cidades com Veículos à Venda', '', 'https://www.temcar.com.br/buscar-cidades/', 1, '2026-05-04 16:59:14'),
(44, 'carros', 'Carros Usados em #cidade, #estado', 'Carros Usados, Novos e Seminovos à venda em #cidade e região, #estado. Compare preços, fale com vendedores e anuncie grátis na TEMCAR.', '', 'Carros à Venda', '', 'https://www.temcar.com.br/carros/usados/#cidade, #estado/', 1, '2026-05-04 17:08:49'),
(45, 'motos', 'Motos Usadas e Novas à venda em #cidade, #estado', 'Motos Usadas, Novas e Seminovas à venda em #cidade e região, #estado. No TEMCAR você encontra ofertas de Motos à venda pelo melhor preço', '', 'motos à venda', '', 'https://www.temcar.com.br/motos/#cidade/#estado/', 1, '2026-05-04 17:08:49'),
(46, 'comprar', 'Comprar Carros Usados em #cidade, #estado', 'Comprar Carros novos, seminovos e usados em #cidade, #estado. no TEMCAR você encontra ofertas de carros pelo melhor preço, confira!', '', 'Comprar Carros Usados', '', '', 1, '2026-05-04 17:08:49'),
(47, 'vender', 'Vender Carro Usado e Seminovo em #cidade, #estado', 'Venda seu Carro Usado e Seminovo em #cidade, #estado. Anuncie e alcance milhares de compradores em todo o Brasil.', 'vender carro, vender moto, anunciar veículo, vender veículo, temcar', 'Vender Carro', '', 'https://www.temcar.com.br/vender/#cidade, #estado', 1, '2026-05-04 17:08:49'),
(54, 'cidade', 'Carros Usados e Novos à venda - #cidade, #estado', 'Carros Usados, Novos, Seminovos à venda em #cidade e região, #estado. No TEMCAR você encontra ofertas de carros à venda esperando por você', '', 'carros novos, seminovos e usados à venda em #cidade, #estado', '', 'https://www.temcar.com.br/cidade/#cidade/#estado/', 1, '2026-05-05 01:57:45'),
